import{_ as e,c as t,o as a,a1 as i}from"./chunks/framework.DqsZw39t.js";const f=JSON.parse('{"title":"Fundamental Database Concepts","description":"","frontmatter":{},"headers":[],"relativePath":"misc/fundamental-database-concepts.md","filePath":"misc/fundamental-database-concepts.md"}'),s={name:"misc/fundamental-database-concepts.md"},n=i('<h1 id="fundamental-database-concepts" tabindex="-1">Fundamental Database Concepts <a class="header-anchor" href="#fundamental-database-concepts" aria-label="Permalink to &quot;Fundamental Database Concepts&quot;">​</a></h1><h2 id="acid-atomicity-consistency-isolation-durability" tabindex="-1">ACID (Atomicity, Consistency, Isolation, Durability) <a class="header-anchor" href="#acid-atomicity-consistency-isolation-durability" aria-label="Permalink to &quot;ACID (Atomicity, Consistency, Isolation, Durability)&quot;">​</a></h2><p><a href="https://en.wikipedia.org/wiki/ACID" target="_blank" rel="noreferrer">ACID</a></p><p>ACID is a set of properties that guarantee the reliability of database transactions. Each letter in ACID stands for a different property:</p><ul><li><p>Atomicity: This property ensures that a transaction is treated as a single, indivisible unit. It either fully succeeds or fully fails. There&#39;s no in-between state. For example, consider transferring money between two bank accounts. If the transfer fails at any point, the entire transaction is rolled back.</p></li><li><p>Consistency: It ensures that a transaction brings the database from one consistent state to another. In other words, the database starts in a consistent state, and after the transaction, it remains consistent. For example, if you have a database storing inventory, a sale transaction should not allow the sale of more items than are in stock.</p></li><li><p>Isolation: This property ensures that concurrent transactions do not interfere with each other. Transactions should be executed in isolation, as if they were the only ones in progress. For example, if two users simultaneously update the same bank account, their transactions should not interfere with each other.</p></li><li><p>Durability: It guarantees that once a transaction is committed, its effects are permanent and will survive system crashes or failures. For example, if a user updates their email address in a database, that change should persist even if the server crashes immediately after the update.</p></li></ul><h2 id="base-basically-available-soft-state-eventually-consistent" tabindex="-1">BASE (Basically Available, Soft state, Eventually consistent) <a class="header-anchor" href="#base-basically-available-soft-state-eventually-consistent" aria-label="Permalink to &quot;BASE (Basically Available, Soft state, Eventually consistent)&quot;">​</a></h2><p><a href="https://en.wikipedia.org/wiki/Eventual_consistency" target="_blank" rel="noreferrer">BASE</a></p><p>BASE is an alternative set of principles for designing distributed databases, often contrasted with ACID. It stands for:</p><ul><li><p>Basically Available: This means that the system should remain operational even in the face of failures. It may not provide immediate or guaranteed consistency but should return some response even if it&#39;s not the most up-to-date.</p></li><li><p>Soft state: The state of the system can change over time due to eventual consistency, which means it may not always reflect the latest data. This soft state is acceptable as long as it eventually converges to a consistent state.</p></li><li><p>Eventually consistent: Unlike ACID&#39;s strong consistency, BASE systems focus on eventual consistency. It acknowledges that in a distributed system, it might take some time for all nodes to reach a consistent state after an update. Users may temporarily see different views of the data.</p></li></ul><h2 id="cap-theorem-consistency-availability-partition-tolerance" tabindex="-1">CAP Theorem (Consistency, Availability, Partition tolerance) <a class="header-anchor" href="#cap-theorem-consistency-availability-partition-tolerance" aria-label="Permalink to &quot;CAP Theorem (Consistency, Availability, Partition tolerance)&quot;">​</a></h2><p><a href="https://en.wikipedia.org/wiki/CAP_theorem" target="_blank" rel="noreferrer">CAP theorem</a></p><p>The CAP theorem is a concept that relates to distributed database systems and states that in a distributed system, you can achieve at most two out of three properties:</p><ul><li><p>Consistency: All nodes in the system see the same data simultaneously. In other words, every read receives the most recent write.</p></li><li><p>Availability: Every request made to the system receives a response, without guaranteeing that it contains the most recent data.</p></li><li><p>Partition tolerance: The system continues to operate even in the presence of network partitions or communication failures.</p></li></ul><p>The CAP theorem suggests that in a distributed system, you must make trade-offs between these properties. For example, if you prioritize consistency and partition tolerance, availability may suffer during network partitions.</p><h2 id="serialization" tabindex="-1"><a href="https://en.wikipedia.org/wiki/Serialization" target="_blank" rel="noreferrer">Serialization</a> <a class="header-anchor" href="#serialization" aria-label="Permalink to &quot;[Serialization](https://en.wikipedia.org/wiki/Serialization)&quot;">​</a></h2><h2 id="books" tabindex="-1">Books <a class="header-anchor" href="#books" aria-label="Permalink to &quot;Books&quot;">​</a></h2><p><a href="https://www.amazon.com/Patterns-Enterprise-Application-Architecture-Martin/dp/0321127420" target="_blank" rel="noreferrer">Patterns of Enterprise Application Architecture - Martin Fowler</a></p><p><a href="https://www.goodreads.com/book/show/13610343-nosql-distilled" target="_blank" rel="noreferrer">NoSQL Distilled</a></p>',18),o=[n];function r(l,c,h,d,p,u){return a(),t("div",null,o)}const y=e(s,[["render",r]]);export{f as __pageData,y as default};
